const PALETTES = {
  'original':   ['#CECECE', '#FFDC5F', '#F59097', '#EB6134', '#1D8EBF', '#07BB7E', '#ECECEC'],
  'neon':       ['#FF00FF', '#00FFFF', '#FF0066', '#CCFF00', '#FF6600', '#6600FF', '#00FF99'],
  'pastels':    ['#FFB3C6', '#FFDDB3', '#FFFFB3', '#B3FFCC', '#B3D9FF', '#D9B3FF', '#FFB3E6'],
  'earth':      ['#8B4513', '#DEB887', '#D2691E', '#8B6914', '#CD853F', '#A0522D', '#F4A460'],
  'monochrome': ['#111111', '#444444', '#666666', '#888888', '#AAAAAA', '#CCCCCC', '#EEEEEE'],
  'warm':       ['#FF4500', '#FF6347', '#FF7F50', '#FFA500', '#FFD700', '#FF8C00', '#DC143C'],
  'cool':       ['#003399', '#0066CC', '#3399FF', '#00CCFF', '#6633FF', '#9933FF', '#33CCCC'],
  'acid':       ['#CCFF00', '#FF0099', '#00FFCC', '#FF6600', '#9900FF', '#FFCC00', '#00FF33']
};

const COMPLEXITIES = {
  'minimal':  { nPoints: 8,  minV: 3, maxV: 4  },
  'moderate': { nPoints: 21, minV: 3, maxV: 7  },
  'dense':    { nPoints: 40, minV: 3, maxV: 9  },
  'extreme':  { nPoints: 70, minV: 3, maxV: 14 }
};

let angleX = 0, angleY = 0, angleZ = 0;
let colors;
let drag = false;
let prevX, prevY;
let points = [], faces = [], faceColors = [], edgeColors = [];
let zoom = 0;
let animStartTime;
let animDuration = 10000;
let bgCol;
let currentPalette = '';
let currentComplexity = '';

function initGeometry() {
  let palName  = p.getSynthVar('color_palette') || 'original';
  let compName = p.getSynthVar('complexity')    || 'moderate';

  colors = PALETTES[palName]       || PALETTES['original'];
  let comp = COMPLEXITIES[compName] || COMPLEXITIES['moderate'];

  points = []; faces = []; faceColors = []; edgeColors = [];

  for (let i = 0; i < comp.nPoints; i++) {
    points.push(p.createVector(
      p.random(-p.width / 4,   p.width / 4),
      p.random(-p.height / 3,  p.height / 3),
      p.random(-p.height / 3.5, p.height / 3.5)
    ));
  }

  for (let i = 0; i < points.length; i++) {
    let face = [];
    let nV = p.int(p.random(comp.minV, comp.maxV));
    for (let j = 0; j < nV; j++) {
      face.push(points[p.floor(p.random(points.length))]);
    }
    faces.push(face);
    faceColors.push(p.random(colors));
    edgeColors.push(p.random(colors));
  }

  let base = p.color(p.random(colors));
  bgCol = p.color(p.red(base) * 0.3, p.green(base) * 0.3, p.blue(base) * 0.3);

  currentPalette    = palName;
  currentComplexity = compName;

  angleX = 0; angleY = 0; angleZ = 0;
  animStartTime = p.millis();

  // Paint the initial background — this is the only clear; trails accumulate from here
  p.background(bgCol);
}

p.setup = function() {
  p.setAttributes({ preserveDrawingBuffer: true, antialias: true });
  p.createCanvas(800, 800, p.WEBGL);
  initGeometry();
};

p.draw = function() {
  // Reinitialise if the user changes palette or complexity
  let pal  = p.getSynthVar('color_palette') || 'original';
  let comp = p.getSynthVar('complexity')    || 'moderate';
  if (pal !== currentPalette || comp !== currentComplexity) {
    initGeometry();
    return;
  }

  let t = (p.millis() - animStartTime) / animDuration;
  if (t > 1) { animStartTime = p.millis(); t = 0; }

  zoom = p.map(p.sin(p.PI * t), -1, 1, -200, 400);

  angleX += p.PI * 3.14 * t / 240;
  angleY += p.PI * 3.14 * t / 1024;
  angleZ += p.PI * 3.14 * t / 38;

  // No background() call — frames accumulate as trails
  p.translate(0, 0, zoom);

  if (drag) {
    angleX += (p.mouseX - prevX) * 0.005;
    angleY -= (p.mouseY - prevY) * 0.005;
  }
  prevX = p.mouseX;
  prevY = p.mouseY;

  p.rotateX(angleX);
  p.rotateY(angleY);
  p.rotateZ(angleZ);
  p.rotateX(angleY);
  p.rotateY(angleX);

  p.strokeWeight(2);
  for (let i = 0; i < faces.length; i++) {
    p.fill(faceColors[i]);
    p.stroke(edgeColors[i]);
    p.beginShape();
    for (let pt of faces[i]) p.vertex(pt.x, pt.y, pt.z);
    p.endShape(p.CLOSE);
  }
};

p.mousePressed  = function() { drag = true; };
p.mouseReleased = function() { drag = false; };
p.mouseWheel    = function(event) { zoom += event.delta * -0.1; return false; };
